#include <stdio.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long sum = 0;
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            if(x % 3 == 0) sum += x;
        }
        printf("%lld\n", sum);
    }
    return 0;
}

